#include <string.h>

int main() {
    char *n[] = {"C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "B", "H"};
    char input[3][3];
    scanf("%s %s %s", input[0], input[1], input[2]);

    int indices[3];
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 12; j++) {
