        for (int j = 0; j < 2 - i; j++) {
            if (indices[j] > indices[j + 1]) {
                int temp = indices[j];
                indices[j] = indices[j + 1];
                indices[j + 1] = temp;
            }
        }
    }

    int c1 = (indices[1] - indices[0] + 12) % 12;
    int c2 = (indices[2] - indices[1] + 12) % 12;

    if ((c1 == 4 && c2 == 3) || (c1 == 3 && c2 == 5) || (c1 == 5 && c2 == 4)) {
        printf("major\n");
